{
  "intent": "check_and_fix",
  "intent_description": "Serial0/1/1 on R2 is oper=lower-layer-down while admin up (likely physical/clocking issue). Serial0/1/1 on R3 is oper=down with admin down (administratively shut). Goal: restore the serial link and correct physical/clocking/administrative state.",
  "target": null,
  "needs_fix": true,
  "plan": {
    "problem": "Asymmetric states on Serial0/1/1: R2 oper=lower-layer-down (admin up) — likely physical layer or clocking issue; R3 oper=down and admin down — interface is administratively shut. Missing info required for full root-cause: exact timestamps; full 'show interfaces Serial0/1/1' output for R2 and R3; 'show running-config interface Serial0/1/1' on R3; 'show controllers serial 0/1/1' on R2 and R3; peer-side interface status; syslog entries around the events.",
    "fix_summary": "1) Re-enable R3 Serial0/1/1 (no shutdown) to restore administrative state. 2) If link remains down (lower-layer-down on R2), assume clocking mismatch and set clock rate 64000 on R2 Serial0/1/1 (assume DCE). Operational risk: changing clocking may affect timing on the circuit.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router3",
        "action": "set_interface_admin_state",
        "target": "Serial0/1/1",
        "parameters": [
          "up"
        ]
      },
      {
        "id": 2,
        "device": "router2",
        "action": "set_interface_clock_rate",
        "target": "Serial0/1/1",
        "parameters": [
          "64000"
        ]
      }
    ]
  }
}

